package ru.memearena.scout.api; import org.springframework.data.domain.*; import org.springframework.web.bind.annotation.*; import org.springframework.security.core.annotation.AuthenticationPrincipal; import ru.memearena.meme.infrastructure.MemeRepository; import ru.memearena.scout.domain.*; import ru.memearena.scout.infrastructure.*; import ru.memearena.security.AuthenticatedUserPrincipal; import java.util.*; import static ru.memearena.scout.api.ScoutDtos.*;
@RestController @RequestMapping("/api/v1/users/me/predictions") public class PredictionController{ private final MemePredictionRepository preds; private final MemeRepository memes; public PredictionController(MemePredictionRepository p,MemeRepository m){this.preds=p;this.memes=m;} @GetMapping public PredictionPageResponse list(@AuthenticationPrincipal AuthenticatedUserPrincipal user,@RequestParam(required=false) PredictionStatus status,@RequestParam(defaultValue="0") int page,@RequestParam(defaultValue="20") int size){page=Math.max(0,page); size=Math.max(1,Math.min(100,size)); Page<MemePrediction> pg=status==null?preds.findByUserId(user.userId(),PageRequest.of(page,size,Sort.by("predictedAt").descending())):preds.findByUserIdAndStatus(user.userId(),status,PageRequest.of(page,size,Sort.by("predictedAt").descending())); Map<UUID,ru.memearena.meme.domain.Meme> ms=new HashMap<>(); memes.findAllByIds(pg.getContent().stream().map(MemePrediction::getMemeId).toList()).forEach(m->ms.put(m.getId(),m)); var items=pg.getContent().stream().map(p->{var m=ms.get(p.getMemeId()); return new PredictionItemResponse(p.getId(),p.getStatus(),new PredictionMemeResponse(p.getMemeId(),m==null?"":m.getTitle(),m==null?null:m.getImageUrl()),p.getBattlesBeforeVote(),p.getPredictedAt(),p.getResolvedAt(),p.getPointsAwarded());}).toList(); return new PredictionPageResponse(items,page,size,pg.getTotalElements(),pg.getTotalPages());}}
